function delete_id_sku(remove_sku){
    let  storage={};
    storage = Storage.prototype.get('session_sku');
         if(storage !=null && storage !=false && remove_sku !=null)
            {
             for (var i = 0; i < storage.length; i++) {
                 //console.log(storage[i]['sku'])
                 if(storage[i]['sku'].length == 0){
                     storage.splice(i,1);  
                 }
                 if(storage[i]['sku'].length>0){
                    let tsku =storage[i]['sku']
                     for (let t=0;t<tsku.length;t++){
                        // console.log(tsku[t],remove_sku)
                         if (remove_sku ==tsku[t]) {
                            tsku.splice(t,1)                       
                         }
                     }
                 }
             }
             window.localStorage.removeItem('session_sku');
             
             Storage.prototype.set('session_sku',storage,180);
            }
}


Storage.prototype.set = (key, value, expire) => {
    if (isNaN(expire) || expire < 1) {
        throw new Error('有效期应为一个有效数值')
    }
    let time = expire * 86_400_000
    let obj = {
        data: value, // 存储值
        time: Date.now(), // 存值时间戳
        expire: time, // 过期时间
    }
    localStorage.setItem(key, JSON.stringify(obj))
}

Storage.prototype.get = key => {
    let val = localStorage.getItem(key)
    if (! val) 
        return val
    
    val = JSON.parse(val)
    if (Date.now() > val.time + val.expire) {
        localStorage.removeItem(key)
        return 'null'
    }
    return val.data
}

Storage.prototype.remove=key=>{
    localStorage.removeItem(key)
}
